import { describe, it, expect } from "vitest";
import { quote, claim } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  describe("quote", () => {
    // --- Empty / single item ---
    it.todo("should return 5 G for an empty item list (processing fee only)");
    it.todo("should return base premium plus fee for a single sword");
    it.todo("should return base premium plus fee for a single amulet");
    it.todo("should return base premium plus fee for a single staff");
    it.todo("should return base premium plus fee for a single potion");

    // --- Components ---
    it.todo("should return 25 G base premium per component for 2 runes");
    it.todo("should return 60 G base premium for a building block of exactly 3 alike components");
    it.todo("should return 25 G per component with no block discount for 4 alike components");
    it.todo("should return separate block premiums for 3 runes and 3 moonstones");
    it.todo("should not apply block discount for 2 runes and 1 moonstone (different types)");

    // --- Item-specific modifiers ---
    it.todo("should add 50% cursed surcharge to the cursed item base premium only");
    it.todo("should add 30% high-enchantment surcharge for enchantment level 5 or above");
    it.todo("should not add high-enchantment surcharge for enchantment level 4");
    it.todo("should apply both cursed and high-enchantment surcharges to the same item");

    // --- Policy-wide modifiers ---
    it.todo("should apply 20% loyalty discount for customers with 2 or more years");
    it.todo("should apply 10% first-insurance surcharge on every quote");
    it.todo("should apply 15% follow-up discount on the second and subsequent quotes");

    // --- Multi-item policies ---
    it.todo("should sum base premiums of multiple different items before applying policy-wide modifiers");
    it.todo("should apply item-specific surcharges only to the affected item in a multi-item policy");

    // --- Integration examples from spec ---
    it.todo("should return 165 G for a newcomer with a cursed sword");
    it.todo("should return 160 G for a long-standing customer's second contract with a cursed enchanted sword");

    // --- Rounding ---
    it.todo("should round premiums up in MHPCO's favor");
  });

  describe("claim", () => {
    // --- Standard reimbursement ---
    it.todo("should reimburse damage minus 100 G deductible for a regular item");

    // --- Dragon material ---
    it.todo("should fully reimburse damage to dragon-material items minus deductible when enchantment is below 8");

    // --- High enchantment ---
    it.todo("should reimburse at 50% of damage amount minus deductible for enchantment 8 or above");

    // --- Both clauses ---
    it.todo("should apply 50% rule when both dragon-material and enchantment >= 8 apply");

    // --- Deductible per item ---
    it.todo("should apply 100 G deductible per damaged item independently");

    // --- Cap ---
    it.todo("should cap total payout at twice the insurance sum");
    it.todo("should track remaining cap across multiple claims on the same policy");

    // --- Rounding ---
    it.todo("should round payouts down in MHPCO's favor");
  });
});

