type Customer = {
  yearsAsCustomer: number;
  quoteCount: number;
};

type Item = {
  type: string;
  material: string;
  enchantment: number;
  cursed: boolean;
};

const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
};

const PROCESSING_FEE = 5;
const FIRST_INSURANCE_RATE = 0.1;

const COMPONENT_BLOCK_SIZE = 3;
const COMPONENT_BLOCK_PREMIUM = 60;
const COMPONENT_TYPES = new Set(["rune", "moonstone"]);

const componentPremium = (type: string, count: number): number =>
  count === COMPONENT_BLOCK_SIZE
    ? COMPONENT_BLOCK_PREMIUM
    : count * BASE_PREMIUMS[type];

export function quote(customer: Customer, items: Item[]): number {
  if (items.length === 0) return PROCESSING_FEE;

  let basePremium = 0;
  const componentCounts: Record<string, number> = {};

  for (const item of items) {
    if (COMPONENT_TYPES.has(item.type)) {
      componentCounts[item.type] = (componentCounts[item.type] || 0) + 1;
    } else {
      basePremium += BASE_PREMIUMS[item.type];
    }
  }

  for (const type of Object.keys(componentCounts)) {
    basePremium += componentPremium(type, componentCounts[type]);
  }

  return basePremium + basePremium * FIRST_INSURANCE_RATE + PROCESSING_FEE;
}

export function claim() {
  return undefined;
}

